input.content:
import { AbsoluteFill, useCurrentFrame, useVideoConfig } from "remotion";
import {
  COLORS,
  GRADIENTS,
  fadeIn,
  fadeOut,
  slideUp,
  typewriter,
  gradientText,
  pulseGlow,
} from "../animations";

// Scene 1: Hook — "Le SEO est mort" (0-8s = 240 frames)
export const Scene1_Hook: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // Phase 1: "Le SEO est mort." dramatic entrance (0-90)
  const seoOpacity = fadeIn(frame, 10, 15);
  const seoY = slideUp(frame, 10, 20);
  const seoStrike = frame > 60 ? 1 : 0;

  // Phase 2: Stats appear (90-180)
  const statOpacity = fadeIn(frame, 95, 20);
  const statY = slideUp(frame, 95, 25);

  // Phase 3: "Vos clients ne cherchent plus..." (130-240)
  const questionOpacity = fadeIn(frame, 140, 20);
  const questionY = slideUp(frame, 140, 25);

  // Global fade out
  const globalFadeOut = fadeOut(frame, 215, 25);

  // Particle grid background
  const gridDots = [];
  for (let x = 0; x < 20; x++) {
    for (let y = 0; y < 12; y++) {
      const delay = (x + y) * 2;
      const dotOpacity = fadeIn(frame, delay, 40) * 0.08 * pulseGlow(frame + delay, 0.03, 0.3, 1);
      gridDots.push(
        <div
          key={`${x}-${y}`}
          style={{
            position: "absolute",
            left: x * 100 + 50,
            top: y * 100 + 30,
            width: 3,
            height: 3,
            borderRadius: "50%",
            background: COLORS.purple,
            opacity: dotOpacity,
          }}
        />
      );
    }
  }

  return (
    <AbsoluteFill
      style={{
        background: GRADIENTS.darkRadial,
        justifyContent: "center",
        alignItems: "center",
        fontFamily: "'Inter', 'Segoe UI', sans-serif",
        opacity: globalFadeOut,
      }}
    >
      {/* Grid background */}
      {gridDots}

      {/* Ambient glow */}
      <div
        style={{
          position: "absolute",
          width: 600,
          height: 600,
          borderRadius: "50%",
          background: "radial-gradient(circle, rgba(168,85,247,0.08) 0%, transparent 70%)",
          top: "50%",
          left: "50%",
          transform: "translate(-50%, -50%)",
          opacity: pulseGlow(frame, 0.04, 0.5, 1),
        }}
      />

      <div style={{ textAlign: "center", position: "relative", zIndex: 2 }}>
        {/* "Le SEO est mort." */}
        <div
          style={{
            opacity: seoOpacity,
            transform: `translateY(${seoY}px)`,
            position: "relative",
          }}
        >
          <span
            style={{
              fontSize: 110,
              fontWeight: 800,
              color: COLORS.white,
              letterSpacing: -3,
              lineHeight: 1.1,
            }}
          >
            Le SEO est{" "}
            <span style={{ position: "relative", display: "inline-block" }}>
              <span
                style={{
                  ...gradientText(GRADIENTS.rose),
                  fontSize: 110,
                  fontWeight: 800,
                }}
              >
                mort
              </span>
              {/* Strike-through animation */}
              <div
                style={{
                  position: "absolute",
                  top: "55%",
                  left: -10,
                  height: 6,
                  background: COLORS.rose,
                  borderRadius: 3,
                  width: seoStrike
                    ? `${Math.min((frame - 60) * 15, 110)}%`
                    : "0%",
                  boxShadow: `0 0 20px ${COLORS.rose}`,
                }}
              />
            </span>
            .
          </span>
        </div>

        {/* Stat: 50% des recherches → IA d'ici 2026 */}
        <div
          style={{
            opacity: statOpacity,
            transform: `translateY(${statY}px)`,
            marginTop: 60,
            display: "flex",
            justifyContent: "center",
            gap: 50,
          }}
        >
          <StatBadge value="50%" label="des recherches vont aux IA" color={COLORS.purple} />
          <StatBadge value="0" label="clics necessaires" color={COLORS.rose} suffix=" clic" />
          <StatBadge value="3x" label="plus de conversions" color={COLORS.green} />
        </div>

        {/* Question line */}
        <div
          style={{
            opacity: questionOpacity,
            transform: `translateY(${questionY}px)`,
            marginTop: 60,
            fontSize: 36,
            color: COLORS.gray,
            fontWeight: 400,
            letterSpacing: 0.5,
          }}
        >
          {typewriter(
            "Vos clients ne cherchent plus sur Google. Ils demandent aux IA.",
            frame,
            145,
            1.2
          )}
          <span
            style={{
              opacity: pulseGlow(frame, 0.1, 0, 1),
              color: COLORS.purple,
            }}
          >
            |
          </span>
        </div>
      </div>
    </AbsoluteFill>
  );
};

// Sub-component: stat badge
const StatBadge: React.FC<{
  value: string;
  label: string;
  color: string;
  suffix?: string;
}> = ({ value, label, color }) => (
  <div
    style={{
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      padding: "20px 30px",
      borderRadius: 16,
      background: `rgba(${hexToRgb(color)}, 0.08)`,
      border: `1px solid rgba(${hexToRgb(color)}, 0.2)`,
    }}
  >
    <span
      style={{
        fontSize: 52,
        fontWeight: 800,
        color,
        letterSpacing: -1,
      }}
    >
      {value}
    </span>
    <span
      style={{
        fontSize: 18,
        color: COLORS.gray,
        marginTop: 4,
        maxWidth: 160,
        textAlign: "center",
        lineHeight: 1.3,
      }}
    >
      {label}
    </span>
  </div>
);

function hexToRgb(hex: string): string {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return `${r},${g},${b}`;
}

