  value: string;
  label: string;
  color: string;
  suffix?: string;
}> = ({ value, label, color }) => (
  <div
    style={{
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      padding: "20px 30px",
      borderRadius: 16,
      background: `rgba(${hexToRgb(color)}, 0.08)`,
      border: `1px solid rgba(${hexToRgb(color)}, 0.2)`,
    }}
  >
    <span
      style={{
        fontSize: 52,
        fontWeight: 800,
        color,
        letterSpacing: -1,
      }}
    >
      {value}
    </span>
    <span
      style={{
        fontSize: 18,
        color: COLORS.gray,
        marginTop: 4,
        maxWidth: 160,
        textAlign: "center",
        lineHeight: 1.3,
      }}
    >
      {label}
    </span>
  </div>
);

function hexToRgb(hex: string): string {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return `${r},${g},${b}`;
}

