import { AbsoluteFill, useCurrentFrame, useVideoConfig, spring } from "remotion";
import {
  COLORS,
  GRADIENTS,
  fadeIn,
  fadeOut,
  slideUp,
  slideDown,
  gradientText,
  pulseGlow,
  scaleSpring,
} from "../animations";

// Scene 2: Brand Reveal (8-16s = 240 frames)
export const Scene2_BrandReveal: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // Phase 1: Logo scale-in with spring (0-60)
  const logoScale = scaleSpring(frame, fps, 15);
  const logoOpacity = fadeIn(frame, 10, 20);

  // Phase 2: Tagline appear (60-120)
  const tagOpacity = fadeIn(frame, 65, 20);
  const tagY = slideUp(frame, 65, 25);

  // Phase 3: AI engines logos orbit (80-200)
  const enginesOpacity = fadeIn(frame, 85, 25);

  // Phase 4: "Premiere plateforme AEO" (130-240)
  const aeoOpacity = fadeIn(frame, 135, 20);
  const aeoY = slideUp(frame, 135, 25);

  // Global fade out
  const globalFade = fadeOut(frame, 215, 25);

  // AI engine names with positions in orbit
  const engines = [
    { name: "ChatGPT", color: "#10a37f", angle: 0 },
    { name: "Claude", color: "#d4a373", angle: 60 },
    { name: "Gemini", color: "#4285f4", angle: 120 },
    { name: "Perplexity", color: "#20b2aa", angle: 180 },
    { name: "Copilot", color: "#0078d4", angle: 240 },
    { name: "AI Overviews", color: "#f43f5e", angle: 300 },
  ];

  return (
    <AbsoluteFill
      style={{
        background: GRADIENTS.darkRadial,
        justifyContent: "center",
        alignItems: "center",
        fontFamily: "'Inter', 'Segoe UI', sans-serif",
        opacity: globalFade,
      }}
    >
      {/* Central glow */}
      <div
        style={{
          position: "absolute",
          width: 800,
          height: 800,
          borderRadius: "50%",
          background: "radial-gradient(circle, rgba(124,58,237,0.15) 0%, transparent 60%)",
          top: "50%",
          left: "50%",
          transform: "translate(-50%, -55%)",
          opacity: pulseGlow(frame, 0.03, 0.6, 1),
        }}
      />

      <div style={{ textAlign: "center", position: "relative", zIndex: 2 }}>
        {/* Logo */}
        <div
          style={{
            opacity: logoOpacity,
            transform: `scale(${logoScale})`,
          }}
        >
          <span
            style={{
              ...gradientText(GRADIENTS.brand),
              fontSize: 120,
              fontWeight: 900,
              letterSpacing: -4,
            }}
          >
            CitedBy
          </span>
          <span
            style={{
              fontSize: 120,
              fontWeight: 300,
              color: COLORS.grayLight,
              letterSpacing: -4,
            }}
          >
            .ai
          </span>
        </div>

        {/* Tagline */}
        <div
          style={{
            opacity: tagOpacity,
            transform: `translateY(${tagY}px)`,
            marginTop: 15,
            fontSize: 32,
            color: COLORS.gray,
            fontWeight: 400,
            letterSpacing: 4,
            textTransform: "uppercase",
          }}
        >
          Faites-vous citer par les IA
        </div>

        {/* AI Engines orbit */}
        <div
          style={{
            opacity: enginesOpacity,
            marginTop: 70,
            position: "relative",
            width: 700,
            height: 120,
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            margin: "70px auto 0",
          }}
        >
          {/* Connecting line */}
          <div
            style={{
              position: "absolute",
              top: "50%",
              left: "5%",
              right: "5%",
              height: 1,
              background: `linear-gradient(90deg, transparent, rgba(168,85,247,0.3), transparent)`,
            }}
          />
          <div style={{ display: "flex", gap: 20, position: "relative" }}>
            {engines.map((engine, i) => {
              const delay = 85 + i * 8;
              const chipScale = scaleSpring(frame, fps, delay);
              const chipOpacity = fadeIn(frame, delay, 15);
              return (
                <div
                  key={engine.name}
                  style={{
                    opacity: chipOpacity,
                    transform: `scale(${chipScale})`,
                    padding: "10px 18px",
                    borderRadius: 12,
                    background: `rgba(${hexToRgb(engine.color)}, 0.1)`,
                    border: `1px solid rgba(${hexToRgb(engine.color)}, 0.3)`,
                    display: "flex",
                    alignItems: "center",
                    gap: 8,
                  }}
                >
                  {/* Dot indicator */}
                  <div
                    style={{
                      width: 8,
                      height: 8,
                      borderRadius: "50%",
                      background: engine.color,
                      boxShadow: `0 0 8px ${engine.color}`,
                    }}
                  />
                  <span
                    style={{
                      fontSize: 16,
                      fontWeight: 600,
                      color: COLORS.white,
                      whiteSpace: "nowrap",
                    }}
                  >
                    {engine.name}
                  </span>
                </div>
              );
            })}
          </div>
        </div>

        {/* AEO label */}
        <div
          style={{
            opacity: aeoOpacity,
            transform: `translateY(${aeoY}px)`,
            marginTop: 55,
          }}
        >
          <span
            style={{
              fontSize: 24,
              fontWeight: 500,
              color: COLORS.grayDark,
              letterSpacing: 1,
            }}
          >
            La premiere plateforme
          </span>
          <span
            style={{
              ...gradientText(GRADIENTS.brand),
              fontSize: 28,
              fontWeight: 700,
              marginLeft: 10,
              letterSpacing: 2,
            }}
          >
            AEO / GEO
          </span>
        </div>
      </div>
    </AbsoluteFill>
  );
};

function hexToRgb(hex: string): string {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return `${r},${g},${b}`;
}

