input.content:
import { AbsoluteFill, useCurrentFrame, useVideoConfig } from "remotion";
import {
  COLORS,
  GRADIENTS,
  fadeIn,
  fadeOut,
  slideUp,
  slideLeft,
  gradientText,
  scaleSpring,
  pulseGlow,
  glassCard,
} from "../animations";

// Scene 3: Features — 3 Pillars + Tools (20s = 600 frames)
export const Scene3_Features: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // Phase 1: "3 piliers" title (0-60)
  const titleOpacity = fadeIn(frame, 10, 20);
  const titleY = slideUp(frame, 10, 25);

  // Phase 2: Pillar cards stagger (60-300)
  const pillars = [
    {
      icon: "🔷",
      name: "Identite",
      subtitle: "GRAPH",
      desc: "Definissez votre entite dans le Knowledge Graph",
      color: "#a855f7",
      tools: ["Source of Truth", "E-E-A-T Builder", "Schema.org"],
    },
    {
      icon: "🧠",
      name: "Semantique",
      subtitle: "RAG",
      desc: "Transformez votre contenu en format Answer-First",
      color: "#06b6d4",
      tools: ["SMC Studio", "Content Writer", "Blog Optimizer"],
    },
    {
      icon: "📡",
      name: "Ubiquite",
      subtitle: "SIGNAL",
      desc: "Multipliez les signaux de corroboration",
      color: "#10b981",
      tools: ["Robots.txt", "llms.txt", "Annuaire Indexe"],
    },
  ];

  // Phase 3: Tools flowing in (300-500)
  const toolsPhaseOpacity = fadeIn(frame, 310, 25);

  // Phase 4: "15 outils generatifs" badge (420-600)
  const badgeOpacity = fadeIn(frame, 430, 20);
  const badgeScale = scaleSpring(frame, fps, 430);

  // Global fade
  const globalFade = fadeOut(frame, 565, 35);

  return (
    <AbsoluteFill
      style={{
        background: GRADIENTS.darkRadial,
        fontFamily: "'Inter', 'Segoe UI', sans-serif",
        opacity: globalFade,
      }}
    >
      {/* Subtle grid */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          backgroundImage: `
            linear-gradient(rgba(168,85,247,0.03) 1px, transparent 1px),
            linear-gradient(90deg, rgba(168,85,247,0.03) 1px, transparent 1px)
          `,
          backgroundSize: "80px 80px",
        }}
      />

      {/* Title */}
      <div
        style={{
          position: "absolute",
          top: 80,
          width: "100%",
          textAlign: "center",
          opacity: titleOpacity,
          transform: `translateY(${titleY}px)`,
        }}
      >
        <span
          style={{
            fontSize: 22,
            fontWeight: 500,
            color: COLORS.purple,
            letterSpacing: 4,
            textTransform: "uppercase",
          }}
        >
          Methodologie
        </span>
        <div style={{ marginTop: 10 }}>
          <span
            style={{
              ...gradientText(GRADIENTS.brand),
              fontSize: 64,
              fontWeight: 800,
              letterSpacing: -2,
            }}
          >
            3 Piliers
          </span>
          <span
            style={{
              fontSize: 64,
              fontWeight: 300,
              color: COLORS.grayLight,
              marginLeft: 15,
            }}
          >
            pour etre cite
          </span>
        </div>
      </div>

      {/* Pillar cards */}
      <div
        style={{
          position: "absolute",
          top: 280,
          width: "100%",
          display: "flex",
          justifyContent: "center",
          gap: 40,
          padding: "0 100px",
        }}
      >
        {pillars.map((pillar, i) => {
          const delay = 70 + i * 40;
          const cardOpacity = fadeIn(frame, delay, 25);
          const cardX = slideLeft(frame, delay, 100, 30);
          const cardScale = scaleSpring(frame, fps, delay);

          return (
            <div
              key={pillar.name}
              style={{
                opacity: cardOpacity,
                transform: `translateX(${cardX}px) scale(${cardScale})`,
                flex: 1,
                maxWidth: 500,
                ...glassCard(0.06),
                padding: "40px 35px",
                position: "relative",
                overflow: "hidden",
              }}
            >
              {/* Top accent line */}
              <div
                style={{
                  position: "absolute",
                  top: 0,
                  left: 0,
                  right: 0,
                  height: 3,
                  background: pillar.color,
                  boxShadow: `0 0 15px ${pillar.color}`,
                }}
              />

              {/* Icon + Label */}
              <div style={{ display: "flex", alignItems: "center", gap: 15, marginBottom: 12 }}>
                <span style={{ fontSize: 36 }}>{pillar.icon}</span>
                <div>
                  <div
                    style={{
                      fontSize: 28,
                      fontWeight: 700,
                      color: COLORS.white,
                    }}
                  >
                    {pillar.name}
                  </div>
                  <div
                    style={{
                      fontSize: 14,
                      fontWeight: 600,
                      color: pillar.color,
                      letterSpacing: 3,
                      textTransform: "uppercase",
                    }}
                  >
                    {pillar.subtitle}
                  </div>
                </div>
              </div>

              {/* Description */}
              <div
                style={{
                  fontSize: 18,
                  color: COLORS.gray,
                  lineHeight: 1.5,
                  marginBottom: 25,
                }}
              >
                {pillar.desc}
              </div>

              {/* Tools list */}
              <div
                style={{
                  opacity: toolsPhaseOpacity,
                  display: "flex",
                  flexDirection: "column",
                  gap: 8,
                }}
              >
                {pillar.tools.map((tool, j) => {
                  const toolDelay = 320 + i * 20 + j * 12;
                  const toolOpacity = fadeIn(frame, toolDelay, 15);
                  const toolX = slideLeft(frame, toolDelay, 30, 15);
                  return (
                    <div
                      key={tool}
                      style={{
                        opacity: toolOpacity,
                        transform: `translateX(${toolX}px)`,
                        display: "flex",
                        alignItems: "center",
                        gap: 10,
                        fontSize: 16,
                        color: COLORS.grayLight,
                      }}
                    >
                      <div
                        style={{
                          width: 6,
                          height: 6,
                          borderRadius: "50%",
                          background: pillar.color,
                          flexShrink: 0,
                        }}
                      />
                      {tool}
                    </div>
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>

      {/* "15 outils generatifs" badge */}
      <div
        style={{
          position: "absolute",
          bottom: 80,
          width: "100%",
          textAlign: "center",
          opacity: badgeOpacity,
          transform: `scale(${badgeScale})`,
        }}
      >
        <div
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: 15,
            padding: "16px 40px",
            borderRadius: 60,
            background: GRADIENTS.brand,
            boxShadow: "0 0 40px rgba(168,85,247,0.3)",
          }}
        >
          <span style={{ fontSize: 36, fontWeight: 800, color: COLORS.white }}>15+</span>
          <span style={{ fontSize: 20, fontWeight: 500, color: "rgba(255,255,255,0.9)" }}>
            outils generatifs propulses par Gemini AI
          </span>
        </div>
      </div>
    </AbsoluteFill>
  );
};

