              <div
                style={{
                  fontSize: 18,
                  color: COLORS.gray,
                  lineHeight: 1.5,
                  marginBottom: 25,
                }}
              >
                {pillar.desc}
              </div>

              {/* Tools list */}
              <div
                style={{
                  opacity: toolsPhaseOpacity,
                  display: "flex",
                  flexDirection: "column",
                  gap: 8,
                }}
              >
                {pillar.tools.map((tool, j) => {
                  const toolDelay = 320 + i * 20 + j * 12;
                  const toolOpacity = fadeIn(frame, toolDelay, 15);
                  const toolX = slideLeft(frame, toolDelay, 30, 15);
                  return (
                    <div
                      key={tool}
                      style={{
                        opacity: toolOpacity,
                        transform: `translateX(${toolX}px)`,
                        display: "flex",
                        alignItems: "center",
                        gap: 10,
                        fontSize: 16,
                        color: COLORS.grayLight,
                      }}
                    >
                      <div
                        style={{
                          width: 6,
                          height: 6,
                          borderRadius: "50%",
                          background: pillar.color,
                          flexShrink: 0,
                        }}
                      />
                      {tool}
                    </div>
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>

      {/* "15 outils generatifs" badge */}
      <div
        style={{
          position: "absolute",
          bottom: 80,
          width: "100%",
          textAlign: "center",
          opacity: badgeOpacity,
          transform: `scale(${badgeScale})`,
        }}
      >
        <div
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: 15,
            padding: "16px 40px",
            borderRadius: 60,
            background: GRADIENTS.brand,
            boxShadow: "0 0 40px rgba(168,85,247,0.3)",
