import { AbsoluteFill, useCurrentFrame, useVideoConfig, interpolate, Easing } from "remotion";
import {
  COLORS,
  GRADIENTS,
  fadeIn,
  fadeOut,
  slideUp,
  gradientText,
  scaleSpring,
  pulseGlow,
  countUp,
  glassCard,
} from "../animations";

// Scene 4: Stats & Dashboard mockup (10s = 300 frames)
export const Scene4_Stats: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // Title
  const titleOpacity = fadeIn(frame, 5, 20);
  const titleY = slideUp(frame, 5, 25);

  // Dashboard mockup
  const dashOpacity = fadeIn(frame, 40, 30);
  const dashScale = interpolate(frame, [40, 75], [0.92, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
    easing: Easing.out(Easing.cubic),
  });

  // KPI counters
  const score = countUp(frame, 60, 0, 78, 40);
  const citationRate = countUp(frame, 70, 0, 68, 40);
  const projects = countUp(frame, 80, 0, 12, 30);

  // Score ring animation
  const ringProgress = interpolate(frame, [60, 120], [0, 0.78], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
    easing: Easing.out(Easing.cubic),
  });

  // AI engines real-time status
  const enginesData = [
    { name: "ChatGPT", score: 82, sentiment: "Positif", color: "#10a37f" },
    { name: "Claude", score: 75, sentiment: "Positif", color: "#d4a373" },
    { name: "Gemini", score: 71, sentiment: "Neutre", color: "#4285f4" },
    { name: "Perplexity", score: 88, sentiment: "Positif", color: "#20b2aa" },
    { name: "AI Overviews", score: 64, sentiment: "Neutre", color: "#f43f5e" },
  ];

  // Global fade
  const globalFade = fadeOut(frame, 270, 30);

  return (
    <AbsoluteFill
      style={{
        background: GRADIENTS.darkRadial,
        fontFamily: "'Inter', 'Segoe UI', sans-serif",
        opacity: globalFade,
      }}
    >
      {/* Title */}
      <div
        style={{
          position: "absolute",
          top: 55,
          width: "100%",
          textAlign: "center",
          opacity: titleOpacity,
          transform: `translateY(${titleY}px)`,
        }}
      >
        <span style={{ fontSize: 20, fontWeight: 500, color: COLORS.purple, letterSpacing: 4, textTransform: "uppercase" }}>
          Tableau de bord
        </span>
        <div style={{ marginTop: 8 }}>
          <span style={{ ...gradientText(GRADIENTS.brand), fontSize: 52, fontWeight: 800, letterSpacing: -2 }}>
            Monitoring temps reel
          </span>
        </div>
      </div>

      {/* Dashboard mockup */}
      <div
        style={{
          position: "absolute",
          top: 200,
          left: "50%",
          transform: `translateX(-50%) scale(${dashScale})`,
          opacity: dashOpacity,
          width: 1600,
        }}
      >
        {/* Top KPI row */}
        <div style={{ display: "flex", gap: 25, marginBottom: 25 }}>
          {/* Score Ring Card */}
          <div style={{ ...glassCard(0.06), padding: "30px 40px", flex: 1, display: "flex", alignItems: "center", gap: 30 }}>
            <svg width="120" height="120" viewBox="0 0 120 120">
              {/* Background ring */}
              <circle cx="60" cy="60" r="50" fill="none" stroke="rgba(168,85,247,0.1)" strokeWidth="10" />
              {/* Progress ring */}
              <circle
                cx="60"
                cy="60"
                r="50"
                fill="none"
                stroke="url(#scoreGrad)"
                strokeWidth="10"
                strokeLinecap="round"
                strokeDasharray={`${ringProgress * 314} 314`}
                transform="rotate(-90 60 60)"
                style={{ filter: "drop-shadow(0 0 8px rgba(168,85,247,0.5))" }}
              />
              <defs>
                <linearGradient id="scoreGrad" x1="0%" y1="0%" x2="100%" y2="0%">
                  <stop offset="0%" stopColor="#a855f7" />
                  <stop offset="100%" stopColor="#7c3aed" />
