                });
                return (
                  <div
                    key={i}
                    style={{
                      width: 12,
                      height: barH,
                      borderRadius: 3,
                      background: i === 9 ? COLORS.cyan : "rgba(6,182,212,0.3)",
                    }}
                  />
                );
              })}
            </div>
          </div>

          {/* Projects */}
          <div style={{ ...glassCard(0.06), padding: "30px 40px", flex: 1 }}>
            <div style={{ fontSize: 16, color: COLORS.gray, marginBottom: 8 }}>Projets Actifs</div>
            <div style={{ fontSize: 48, fontWeight: 800, color: COLORS.purple, letterSpacing: -1 }}>
              {projects}
            </div>
            <div style={{ fontSize: 14, color: COLORS.gray, marginTop: 8 }}>3 audits en cours</div>
          </div>
        </div>

        {/* AI Engines Status Row */}
        <div style={{ ...glassCard(0.04), padding: "25px 35px" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
            <span style={{ fontSize: 18, fontWeight: 600, color: COLORS.white }}>Citation par moteur IA</span>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <div
                style={{
                  width: 8,
                  height: 8,
                  borderRadius: "50%",
                  background: COLORS.green,
                  boxShadow: `0 0 6px ${COLORS.green}`,
                  opacity: pulseGlow(frame, 0.1, 0.5, 1),
                }}
              />
              <span style={{ fontSize: 14, color: COLORS.green }}>Live</span>
            </div>
          </div>

          <div style={{ display: "flex", gap: 20 }}>
            {enginesData.map((engine, i) => {
              const eDelay = 120 + i * 15;
              const eOpacity = fadeIn(frame, eDelay, 20);
              const eScore = countUp(frame, eDelay, 0, engine.score, 30);
              const barWidth = interpolate(frame, [eDelay, eDelay + 30], [0, engine.score], {
                extrapolateLeft: "clamp",
                extrapolateRight: "clamp",
                easing: Easing.out(Easing.cubic),
              });

              return (
                <div key={engine.name} style={{ flex: 1, opacity: eOpacity }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                      <div style={{ width: 8, height: 8, borderRadius: "50%", background: engine.color }} />
                      <span style={{ fontSize: 15, fontWeight: 600, color: COLORS.white }}>{engine.name}</span>
                    </div>
                    <span style={{ fontSize: 14, color: engine.color, fontWeight: 700 }}>{eScore}%</span>
                  </div>
                  {/* Progress bar */}
                  <div style={{ height: 6, borderRadius: 3, background: "rgba(255,255,255,0.05)" }}>
                    <div
                      style={{
                        height: "100%",
                        width: `${barWidth}%`,
                        borderRadius: 3,
                        background: engine.color,
                        boxShadow: `0 0 10px ${engine.color}40`,
                      }}
                    />
                  </div>
                  <div style={{ fontSize: 12, color: COLORS.grayDark, marginTop: 6 }}>{engine.sentiment}</div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </AbsoluteFill>
  );
};

