import { AbsoluteFill, useCurrentFrame, useVideoConfig, interpolate, Easing } from "remotion";
import {
  COLORS,
  GRADIENTS,
  fadeIn,
  fadeOut,
  slideUp,
  slideDown,
  gradientText,
  scaleSpring,
  pulseGlow,
  typewriter,
} from "../animations";

// Scene 5: CTA & Closing (8s = 240 frames)
export const Scene5_CTA: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // Phase 1: "Pret a etre cite ?" (0-60)
  const headOpacity = fadeIn(frame, 10, 20);
  const headY = slideUp(frame, 10, 25);

  // Phase 2: Value props recap (50-130)
  const props = [
    { icon: "⚡", text: "Audit gratuit en 30 secondes" },
    { icon: "💳", text: "0 carte bancaire requise" },
    { icon: "🇫🇷", text: "Made in France — RGPD" },
  ];

  // Phase 3: CTA button (110-180)
  const ctaOpacity = fadeIn(frame, 115, 20);
  const ctaScale = scaleSpring(frame, fps, 115);
  const ctaPulse = pulseGlow(frame, 0.06, 0.7, 1);

  // Phase 4: URL (150-240)
  const urlOpacity = fadeIn(frame, 155, 20);
  const urlY = slideUp(frame, 155, 20);

  // Phase 5: Trust badges (170-240)
  const trustOpacity = fadeIn(frame, 175, 20);

  // Particles rising
  const particles = Array.from({ length: 30 }, (_, i) => {
    const x = 100 + (i * 61) % 1720;
    const speed = 0.5 + (i % 5) * 0.3;
    const size = 2 + (i % 3);
    const startY = 1100 - ((frame * speed + i * 40) % 1200);
    const particleOpacity = interpolate(startY, [0, 200, 900, 1100], [0, 0.3, 0.3, 0], {
      extrapolateLeft: "clamp",
      extrapolateRight: "clamp",
    });
    return (
      <div
        key={i}
        style={{
          position: "absolute",
          left: x,
          top: startY,
          width: size,
          height: size,
          borderRadius: "50%",
          background: i % 3 === 0 ? COLORS.purple : i % 3 === 1 ? COLORS.violet : COLORS.rose,
          opacity: particleOpacity * 0.4,
        }}
      />
    );
  });

  return (
    <AbsoluteFill
      style={{
        background: GRADIENTS.darkRadial,
        justifyContent: "center",
        alignItems: "center",
        fontFamily: "'Inter', 'Segoe UI', sans-serif",
      }}
    >
      {/* Rising particles */}
      {particles}

      {/* Large background glow */}
      <div
        style={{
          position: "absolute",
          width: 1000,
          height: 1000,
          borderRadius: "50%",
