 268→  const monthlyProjectCount = useMemo(() => {
 269→    if (history.length === 0) return 0;
 270→
 271→    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
 272→    const now = new Date();
 273→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
 274→
 275→    // 1. Identifier la date de création (première analyse) de chaque domaine
 276→    const projectCreationDates = new Map<string, Date>();
 277→    
 278→    history.forEach(h => {
 279→        let hostname;
 280→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
 281→        
 282→        const analysisDate = new Date(h.timestamp);
 283→        
 284→        if (!projectCreationDates.has(hostname)) {
 285→            projectCreationDates.set(hostname, analysisDate);
 286→        } else {
 287→            // On garde la date la plus ancienne trouvée pour ce domaine
 288→            if (analysisDate < projectCreationDates.get(hostname)!) {
 289→                projectCreationDates.set(hostname, analysisDate);
 290→            }
 291→        }
 292→    });
 293→
 294→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
 295→    let count = 0;
 296→    projectCreationDates.forEach((creationDate) => {
 297→        if (creationDate >= billingCycleStart) {
 298→            count++;
 299→        }
 300→    });
 301→    
 302→    return count;
 303→  }, [history]);
